#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        long long dp[M] = {0};
        dp[0] = 1;
        for (int i = 1; i < M; i++) {
            dp[i] = dp[i - 1];
        }
        for (int i = M; i <= N; i++) {
            long long sum = 0;
            for (int j = 1; j <= M; j++) {
                sum = (sum + dp[(i - j) % M]) % MOD;
            }
            dp[i % M] = sum;
        }
        printf("%lld\n", dp[N % M]);
    }
    return 0;
}

